namespace sv_daa45ab3d781492fbc661d96a8d28331.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_daa45ab3d781492fbc661d96a8d28331.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="catalog-layout d-flex gap-4">
    @* ───── Left Sidebar (Filters) ───── *@
    <aside class="catalog-sidebar">
        <h5>Filters</h5>

        @* Category checkboxes *@
        <div class="mb-3">
            <label class="form-label fw-semibold">Categories</label>
            @if (categories is not null)
            {
                @foreach (var cat in categories)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                               checked="@selectedCategories.Contains(cat)"
                               @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                        <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                    </div>
                }
            }
            else
            {
                <p class="text-muted small">Loading…</p>
            }
        </div>

        @* Price range *@
        <div class="mb-3">
            <label class="form-label fw-semibold">Price Range</label>
            <div class="d-flex gap-2">
                <input type="number" class="form-control form-control-sm" placeholder="Min"
                       @bind="minPrice" min="0" step="0.01" />
                <input type="number" class="form-control form-control-sm" placeholder="Max"
                       @bind="maxPrice" min="0" step="0.01" />
            </div>
        </div>

        @* In stock toggle *@
        <div class="form-check mb-3">
            <input class="form-check-input" type="checkbox" id="inStockOnly"
                   @bind="inStockOnly" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>

        <div class="d-grid gap-2">
            <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    @* ───── Main Content ───── *@
    <section class="catalog-main flex-grow-1">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger">@errorMessage</div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else if (result is null || result.Items.Count == 0)
        {
            <div class="alert alert-info">No products found. Try adjusting your filters.</div>
        }
        else
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
                <div class="d-flex align-items-center gap-2">
                    <label class="form-label mb-0 fw-semibold" for="sortSelect">Sort by:</label>
                    <select id="sortSelect" class="form-select form-select-sm w-auto" @bind="sortBy"
                            @bind:after="LoadProductsAsync">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted small">
                    Showing @(StartItem)–@(EndItem) of @result.TotalCount products
                </span>
            </div>

            @* Product grid *@
            <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3 mb-4">
                @foreach (var product in result.Items)
                {
                    <div class="col">
                        <ProductCard Product="product"
                                     OnProductSelected="HandleProductSelected"
                                     OnAddToCart="HandleAddToCart" />
                    </div>
                }
            </div>

            @* Pagination *@
            <nav aria-label="Product pagination">
                <ul class="pagination justify-content-center flex-wrap">
                    <li class="page-item @(currentPage <= 1 ? "disabled" : "")">
                        <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
                                disabled="@(currentPage <= 1)">Previous</button>
                    </li>
                    @for (int i = 1; i <= TotalPages; i++)
                    {
                        var pageNum = i;
                        <li class="page-item @(pageNum == currentPage ? "active" : "")">
                            <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                        </li>
                    }
                    <li class="page-item @(currentPage >= TotalPages ? "disabled" : "")">
                        <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
                                disabled="@(currentPage >= TotalPages)">Next</button>
                    </li>
                </ul>
            </nav>
        }
    </section>
</div>

@code {
    private const int PageSize = 9;

    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;

    private PagedResult<Product>? result;
    private bool isLoading = true;
    private string? errorMessage;

    private int TotalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / PageSize);

    private int StartItem => result is null || result.Items.Count == 0
        ? 0
        : (result.Page - 1) * PageSize + 1;

    private int EndItem => result is null
        ? 0
        : (result.Page - 1) * PageSize + result.Items.Count;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = LoadProductsCoreAsync();
            await Task.WhenAll(categoriesTask, productsTask);
            categories = categoriesTask.Result;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load catalog: {ex.Message}";
            isLoading = false;
        }
    }

    private async Task LoadProductsAsync()
    {
        try
        {
            errorMessage = null;
            isLoading = true;
            await LoadProductsCoreAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task LoadProductsCoreAsync()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly);

        result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        isLoading = false;
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        currentPage = page;
        await LoadProductsAsync();
    }

    private void HandleProductSelected(Product product)
    {
        // Parent-level navigation hook — wire up NavigationManager or a parent callback as needed.
    }

    private void HandleAddToCart(Product product)
    {
        // Cart integration point.
    }
}

.catalog-layout {
    min-height: 60vh;
}

.catalog-sidebar {
    width: 25%;
    min-width: 200px;
    max-width: 300px;
    flex-shrink: 0;
    padding: 1rem;
    border-right: 1px solid var(--bs-border-color, #dee2e6);
}

.catalog-main {
    width: 75%;
}

@media (max-width: 768px) {
    .catalog-layout {
        flex-direction: column;
    }

    .catalog-sidebar {
        width: 100%;
        max-width: none;
        border-right: none;
        border-bottom: 1px solid var(--bs-border-color, #dee2e6);
        padding-bottom: 1rem;
        margin-bottom: 1rem;
    }

    .catalog-main {
        width: 100%;
    }
}

@using sv_daa45ab3d781492fbc661d96a8d28331.Services

<div class="card h-100 product-card" @onclick="OnCardClicked" role="button" tabindex="0">
    <div class="product-image-placeholder d-flex align-items-center justify-content-center bg-light"
         role="img" aria-label="@Product.Name">
        <span class="text-muted small text-center px-2">@Product.Name</span>
    </div>

    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="card-text mb-2" aria-label="@($"Rating: {RatingValue} out of 5")">
            @RatingStars
        </p>

        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }

        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="OnAddToCartClicked"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private int RatingValue => (int)Math.Round(Product.Rating);

    private string RatingStars
    {
        get
        {
            int filled = Math.Clamp(RatingValue, 0, 5);
            return new string('★', filled) + new string('☆', 5 - filled);
        }
    }

    private async Task OnCardClicked()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task OnAddToCartClicked()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }
}

.product-card {
    cursor: pointer;
    transition: box-shadow 0.15s ease-in-out, transform 0.15s ease-in-out;
}

.product-card:hover {
    box-shadow: 0 0.25rem 0.75rem rgba(0, 0, 0, 0.15);
    transform: translateY(-2px);
}

.product-image-placeholder {
    height: 180px;
    border-bottom: 1px solid var(--bs-border-color, #dee2e6);
}

